prompt.state_management_pattern:
```typescript
// useCoachState.ts — 单 useReducer 管理全部全局状态

interface CoachState {
  sessionId: string | null;
  token: string | null;
  ttmStage: TTMStage;
  messages: ChatMessage[];
  pulse: PulseState | null;
  excursion: boolean;
  gates: GateSummary | null;
  adminMode: boolean;
  error: string | null;
  loading: boolean;
}

const initialState: CoachState = {
  sessionId: null,
  token: null,
  ttmStage: 'unknown',
  messages: [],
  pulse: null,
  excursion: false,
  gates: null,
  adminMode: false,
  error: null,
  loading: false,
};

type CoachAction =
  | { type: 'SET_SESSION'; sessionId: string; token: string }
  | { type: 'ADD_MESSAGE'; message: ChatMessage }
  | { type: 'SET_TTM_STAGE'; stage: TTMStage }
  | { type: 'SET_PULSE'; pulse: PulseState | null }
  | { type: 'SET_EXCURSION'; active: boolean }
  | { type: 'SET_GATES'; gates: GateSummary }
  | { type: 'SET_LOADING'; loading: boolean }
  | { type: 'SET_ERROR'; error: string | null };

function coachReducer(state: CoachState, action: CoachAction): CoachState {
  switch (action.type) {
    case 'SET_SESSION':
      return { ...state, sessionId: action.sessionId, token: action.token };
    case 'ADD_MESSAGE':
      return { ...state, messages: [...state.messages, action.message] };
    // ... 其他 case
    default:
      return state;
  }
}
```

prompt.websocket_pattern:
```typescript
// useWebSocket.ts — WS 连接生命周期管理

export function useWebSocket(dispatch: React.Dispatch) {
  const wsRef = useRef(null);
  const reconnectAttempts = useRef(0);

  useEffect(() => {
    function connect() {
      const ws = new WebSocket(`ws://localhost:8001/api/v1/chat/ws`);
      wsRef.current = ws;

      ws.onopen = () => { reconnectAttempts.current = 0; };

      ws.onmessage = (event) => {
        const msg = JSON.parse(event.data);
        switch (msg.type) {
          case 'coach_response':
            dispatch({ type: 'ADD_MESSAGE', message: msg.payload });
            break;
          case 'pulse_event':
            dispatch({ type: 'SET_PULSE', pulse: msg });
            break;
          case 'error':
            dispatch({ type: 'SET_ERROR', error: msg.detail });
            break;
        }
      };

      ws.onclose = () => {
        if (reconnectAttempts.current < 3) {
          setTimeout(connect, 1000 * Math.pow(2, reconnectAttempts.current));
          reconnectAttempts.current++;
        }
      };
    }
    connect();
    return () => { wsRef.current?.close(); };
  }, []);
}
```

