// stateMachine.ts — 完整的 TTM 6 态映射（含 unknown）
export type TTMStage = 'unknown' | 'precontemplation' | 'contemplation'
  | 'preparation' | 'action' | 'maintenance' | 'relapse';

export const TTM_UI_MAP: Record = {
  unknown: {
    theme: 'minimal',
    inputMode: 'suggest_only',
    pulseMode: 'disabled',
    description: '新用户默认态 — 极简界面，最少交互要求',
  },
  precontemplation: {
    theme: 'minimal',
    inputMode: 'suggest_only',
    pulseMode: 'disabled',
    description: '极简环境数据看板; 低频微轻推(Nudges); 客观信息图表',
  },
  contemplation: {
    theme: 'balanced',
    inputMode: 'reflect_first',
    pulseMode: 'gentle',
    description: '对比式Pros vs Cons决策平衡卡片; 用户故事轮播; 动态收益进度条',
  },
  preparation: {
    theme: 'active',
    inputMode: 'scaffold',
    pulseMode: 'commitment',
    description: '交互式目标拆解向导(Stepper); 微习惯日程表; 一键承诺确认按钮',
  },
  action: {
    theme: 'energetic',
    inputMode: 'checkin',
    pulseMode: 'high_frequency',
    description: '动态发光进度环; 全屏撒花动效; 一键式学习签到',
  },
  maintenance: {
    theme: 'calm',
    inputMode: 'explore',
    pulseMode: 'milestone',
    description: '连续打卡日历热力图; 数字成就徽章墙; 高阶探险解锁通知',
  },
  relapse: {
    theme: 'gentle',
    inputMode: 'recover',
    pulseMode: 'none',
    description: '破冰式关怀对话卡片("重新开始是旅程的一部分"); 一键恢复历史进度时光机',
  },
} as const;
